mapper.select:
SELECT c.courseId, c.courseName, c.credits, t.Name AS teacherName
FROM course c
JOIN teacher t ON c.TeacherID = t.TeacherID;

SELECT * FROM student WHERE 1=1

    AND student_no LIKE CONCAT('%', #{studentNo}, '%')


    AND Name LIKE CONCAT('%', #{studentName}, '%')


    AND DeptID IN (
    SELECT DeptID FROM department
    WHERE DeptName LIKE CONCAT('%', #{studentDept}, '%')
    )


    AND DOB LIKE CONCAT('%', #{studentDOB}, '%')


    AND Gender = #{studentSex}

LIMIT #{offset}, #{limit}
